function projectRootHref(){
  const clean = location.href.split('#')[0].split('?')[0];
  if (/\/masks\/[^/]+\/[^/]+$/.test(clean)) return clean.replace(/\/masks\/[^/]+\/[^/]+$/, '/');
  if (/\/tools\/[^/]+$/.test(clean)) return clean.replace(/\/tools\/[^/]+$/, '/');
  if (/\/src\/core\/[^/]+$/.test(clean)) return clean.replace(/\/src\/core\/[^/]+$/, '/');
  if (/\/index\.html$/.test(clean)) return clean.replace(/\/index\.html$/, '/');
  return clean.replace(/[^/]*$/, '');
}
function routePath(input){
  if(!input) return input;
  const raw = String(input);
  const hashSplit = raw.split('#');
  const rawNoHash = hashSplit[0];
  const hash = hashSplit.length > 1 ? '#' + hashSplit.slice(1).join('#') : '';
  const querySplit = rawNoHash.split('?');
  const base = querySplit[0];
  const query = querySplit.length > 1 ? '?' + querySplit.slice(1).join('?') : '';
  const mapped = ROUTE_MAP[base] || base;
  return new URL(mapped + query + hash, projectRootHref()).href;
}

