function safeGetText(key){
  try{ const v = localStorage.getItem(key); if(v!=null) return v; }catch(_e){}
  try{ const v = sessionStorage.getItem(key); if(v!=null) return v; }catch(_e){}
  return null;
}
function safeSetText(key,val){
  try{ localStorage.setItem(key, String(val)); return true; }catch(_e){}
  try{ sessionStorage.setItem(key, String(val)); return true; }catch(_e){}
  return false;
}
function safeRemoveKey(key){
  try{ localStorage.removeItem(key); }catch(_e){}
  try{ sessionStorage.removeItem(key); }catch(_e){}
}
function clearAllKFStorage(){
  const stores=[typeof localStorage!=='undefined' ? localStorage : null, typeof sessionStorage!=='undefined' ? sessionStorage : null].filter(Boolean);
  stores.forEach(store=>{
    try{
      const keys=[];
      for(let i=0;i<store.length;i++){ const k=store.key(i); if(k && k.indexOf('kf.')===0) keys.push(k); }
      keys.forEach(k=>{ try{ store.removeItem(k); }catch(_e){} });
    }catch(_e){}
  });
  try{ if(window && window.top===window) window.name=''; }catch(_e){}
}
function readWindowCarrier(targetWindow){
  try{
    const ref = targetWindow || window;
    const raw = ref && typeof ref.name==='string' ? ref.name : '';
    if(!raw || raw.indexOf('{')!==0) return null;
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed==='object' ? parsed : null;
  }catch(_e){ return null; }
}
function writeWindowCarrier(patch, targetWindow){
  try{
    const ref = targetWindow || window;
    const next = { ...(readWindowCarrier(ref) || {}), ...(patch || {}) };
    ref.name = JSON.stringify(next);
    return next;
  }catch(_e){ return null; }
}
function carrierGet(key, targetWindow){
  const bag = readWindowCarrier(targetWindow);
  return bag && Object.prototype.hasOwnProperty.call(bag, key) ? bag[key] : null;
}
function carrierSet(key, value, targetWindow){
  const patch = {}; patch[key] = value;
  return writeWindowCarrier(patch, targetWindow);
}
function parentCarrierGet(key){
  try{ if(window.parent && window.parent !== window) return carrierGet(key, window.parent); }catch(_e){}
  return null;
}
function setEmbedStateSnapshot(state){
  runtimeStore().embedStateSnapshot = state || null;
  carrierSet('embedState', state || null);
  if(state){ try{ setJSON(STORAGE_KEYS.embedState, state); }catch(_e){} }
  else safeRemoveKey(STORAGE_KEYS.embedState);
  return runtimeStore().embedStateSnapshot;
}
function getEmbedStateSnapshot(){ return runtimeStore().embedStateSnapshot || carrierGet('embedState') || getJSON(STORAGE_KEYS.embedState) || null; }
function parentEmbedStateSnapshot(){
  try{
    if(window.parent && window.parent !== window){
      if(window.parent.__KF_RUNTIME && window.parent.__KF_RUNTIME.embedStateSnapshot) return window.parent.__KF_RUNTIME.embedStateSnapshot;
      const parentCarrier = parentCarrierGet('embedState');
      if(parentCarrier) return parentCarrier;
      if(window.parent.KFApp && typeof window.parent.KFApp.getEmbedStateSnapshot==='function') return window.parent.KFApp.getEmbedStateSnapshot() || null;
    }
  }catch(_e){}
  return null;
}
function setPopupPayload(payload){ runtimeStore().popupPayload = payload || null; carrierSet('popupPayload', payload || null); return runtimeStore().popupPayload; }
function getPopupPayload(){ return runtimeStore().popupPayload || carrierGet('popupPayload') || null; }
function parentPopupPayload(){ try{ if(window.parent && window.parent !== window){ return (window.parent.__KF_RUNTIME && window.parent.__KF_RUNTIME.popupPayload) || parentCarrierGet('popupPayload') || null; } }catch(_e){} return null; }


