function qsa(sel,root=document){ return Array.from(root.querySelectorAll(sel)); }
function clamp(v,min,max){ return Math.max(min, Math.min(max, v)); }
function rnd(seed){ let s=0; const str=String(seed); for(let i=0;i<str.length;i++) s=(s*31+str.charCodeAt(i))>>>0; if(!s) s=123456789; return ()=>{ s=(1664525*s+1013904223)>>>0; return s/4294967296; }; }
