function weightedPick(items, weightFn, r){ const weighted=items.map(item=>({item,w:Math.max(0, Number(weightFn(item)||0))})).filter(x=>x.w>0); if(!weighted.length) return items[0]||null; const total=weighted.reduce((a,b)=>a+b.w,0); let t=r()*total; for(const x of weighted){ t-=x.w; if(t<=0) return x.item; } return weighted[weighted.length-1].item; }
function sampleWithoutReplacement(items,count,r){ const pool=[...items], out=[]; while(pool.length&&out.length<count){ out.push(pool.splice(randomInt(r,0,pool.length-1),1)[0]); } return out; }
function average(values){ const nums=values.map(Number).filter(Number.isFinite); return nums.length ? nums.reduce((a,b)=>a+b,0)/nums.length : 0; }
function sum(values){ return values.map(Number).filter(Number.isFinite).reduce((a,b)=>a+b,0); }
function slugify(str){ return String(str).toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/[^a-z0-9]+/g,'_').replace(/^_+|_+$/g,''); }
function deepClone(v){ return JSON.parse(JSON.stringify(v)); }
function setJSON(key,val){ const text=JSON.stringify(val); safeSetText(key, text); }
