function fmtMio(v){ return Number(v||0).toFixed(2).replace('.',',') + ' Mio.'; }
function fmtOne(v){ return Number(v||0).toFixed(1).replace('.',','); }
function seasonCurrencyToMillions(v){ return Number((Number(v||0)/1000000).toFixed(2)); }
