function getLeaguesByCountry(countryName){ return [...new Set(KFDB.clubs.filter(c=>c.countryName===countryName).map(c=>c.leagueKey))].sort((a,b)=>{ const la=getLeagueRef(a)?.leagueLevel||99, lb=getLeagueRef(b)?.leagueLevel||99; return la-lb || a.localeCompare(b,'de');}); }
