function getNationGroupMap(){ return Object.fromEntries(KFDB.nationGroups.map(x=>[x.nationality, x.groupKey||x.group||x.nationGroup])); }
const nationGroupMap = getNationGroupMap();
function chooseNationality(leagueKey,r){ const rows = KFDB.nationalityDistribution.filter(x=>x.leagueKey===leagueKey); const picked = weightedPick(rows, x=>x.sharePercent||x.share||1, r)?.nationality || 'Deutschland'; if(picked !== 'Sonstige') return picked; const used = new Set(rows.filter(x=>x.nationality!=='Sonstige').map(x=>x.nationality)); const all = [...new Set([...(KFDB.firstNames||[]).map(x=>x.nationality||x.nation), ...(KFDB.lastNames||[]).map(x=>x.nationality||x.nation)].filter(Boolean))].filter(n=>n!=='Sonstige' && !used.has(n)); if(!all.length) return rows.find(x=>x.nationality!=='Sonstige')?.nationality || 'Deutschland'; return all[randomInt(r,0,all.length-1)]; }
function ageBucket(age){ if(age<=19) return 'u20'; if(age<=24) return 'age20to24'; if(age<=29) return 'age25to29'; return 'age30plus'; }
function chooseAge(r){ const dist=[{min:17,max:19,w:18},{min:20,max:23,w:30},{min:24,max:27,w:27},{min:28,max:31,w:18},{min:32,max:35,w:7}]; const bucket=weightedPick(dist,x=>x.w,r); return randomInt(r,bucket.min,bucket.max); }
function chooseFirstName(nationality, age, r){ const rows=KFDB.firstNames.filter(x=>x.nationality===nationality||x.nation===nationality); const field = age<=20 ? 'age15to20' : age<=25 ? 'age20to25' : age<=30 ? 'age25to30' : 'age30plus'; return weightedPick(rows.length?rows:KFDB.firstNames.slice(0,50), x=>x.ageWeights?.[field] || x[field] || 1, r)?.firstName || 'Alex'; }
function chooseLastName(nationality, r){ const rows=KFDB.lastNames.filter(x=>x.nationality===nationality||x.nation===nationality); return weightedPick(rows.length?rows:KFDB.lastNames.slice(0,50), x=>x.weight||x.frequency||x['Häufigkeit']||1, r)?.lastName || 'Meyer'; }
function chooseMainPositionForGroup(groupKey,r){ const map={TW:['TW'],IV:['IV'],FB:['LV','RV'],CM:['DM','ZM','OM'],WM:['LM','RM'],ST:['LF','HS','ST','RF']}; return weightedPick(map[groupKey]||['ZM'], ()=>1, r); }
function chooseSecondaryPositions(mainPosition,r){ const map={TW:[],LV:['LM','IV'],RV:['RM','IV'],IV:['DM'],DM:['IV','ZM'],ZM:['DM','OM'],OM:['ZM','HS'],LM:['LV','LF'],RM:['RV','RF'],LF:['LM','ST'],RF:['RM','ST'],HS:['OM','ST'],ST:['HS','LF','RF']}; const candidates=map[mainPosition]||[]; if(!candidates.length) return [null,null]; const count=weightedPick([0,1,2], x=>({0:35,1:45,2:20}[x]), r); const selected=sampleWithoutReplacement(candidates,count,r); return [selected[0]||null, selected[1]||null]; }
function chooseCharacterKeys(nationality,r){ const nationGroup=nationGroupMap[nationality]||'BAL'; const defs=KFDB.characterDefinitions; const count=weightedPick([0,1,2], x=>({0:15,1:60,2:25}[x]), r); if(count===0) return [null,null]; const pool=[...defs]; const out=[]; while(out.length<count && pool.length){ const pick=weightedPick(pool, d=>Number(d.groupWeights?.[nationGroup]||1), r); out.push(pick); pool.splice(pool.findIndex(x=>x.key===pick.key),1); } return [out[0]||null,out[1]||null]; }
function chooseTypeKeys(mainPosition,r){ const defs=KFDB.playerTypeDefinitions.filter(d=>d.availableAtGameStart!==false); const count=weightedPick([0,1,2], x=>({0:10,1:65,2:25}[x]), r); if(count===0) return [null,null]; const pool=[...defs]; const out=[]; while(out.length<count&&pool.length){ const pick=weightedPick(pool, d=>Number(d.positionWeights?.[mainPosition]||1), r); out.push(pick); pool.splice(pool.findIndex(x=>x.key===pick.key),1); } return [out[0]||null,out[1]||null]; }
function buildSkillValue(r, anchor, jitter=4){ return clamp(Math.round(anchor + (r()*(jitter*2)-jitter)),1,99); }
function buildSkillProfile(mainPosition, targetOverall, r){ const w=POSITION_GROUP_SKILL_TARGETS[mainPosition]||POSITION_GROUP_SKILL_TARGETS.ZM; const anchors={ tech:targetOverall+Math.round((w.tech-.18)*20), fin:targetOverall+Math.round((w.fin-.12)*20), mental:targetOverall+Math.round((w.mental-.18)*18), phys:targetOverall+Math.round((w.phys-.18)*18), def:targetOverall+Math.round((w.def-.16)*22), gk: mainPosition==='TW'?targetOverall+5:8}; const profile={}; for(const [group,attrs] of Object.entries(SKILL_GROUPS)){ for(const attr of attrs){ profile[attr]=buildSkillValue(r, anchors[group], group==='gk'&&mainPosition!=='TW'?2:5); } } if(mainPosition!=='TW'){ for(const attr of SKILL_GROUPS.gk) profile[attr]=clamp(profile[attr],1,20); } else { for(const attr of ['finishing','longShots','heading','setPieces']) profile[attr]=clamp(profile[attr],1,35); } return profile; }
function calcRatings(player){ return { techRating:average([player.ballControl,player.dribbling,player.shortPassing,player.longPassing,player.crossing]), finishingRating:average([player.finishing,player.longShots,player.heading,player.setPieces,player.techniqueFlair]), mentalRating:average([player.vision,player.decisionMaking,player.positioning,player.teamwork,player.concentration]), physicalRating:average([player.speed,player.acceleration,player.stamina,player.strengthPhysical,player.balance]), defensiveRating:average([player.tackling,player.aggression,player.composure,player.leadership,player.discipline]), goalkeepingRating:average([player.gkReflexes,player.gkAreaControl,player.gkKicking,player.gkOneOnOne,player.gkHandling]) }; }
const OVERALL_WEIGHTS={TW:{goalkeepingRating:.70,mentalRating:.10,physicalRating:.10,techRating:.10},LV:{defensiveRating:.28,physicalRating:.22,techRating:.22,mentalRating:.18,finishingRating:.10},RV:{defensiveRating:.28,physicalRating:.22,techRating:.22,mentalRating:.18,finishingRating:.10},IV:{defensiveRating:.35,physicalRating:.25,mentalRating:.20,techRating:.15,finishingRating:.05},DM:{defensiveRating:.28,mentalRating:.24,techRating:.22,physicalRating:.18,finishingRating:.08},ZM:{techRating:.28,mentalRating:.24,physicalRating:.20,defensiveRating:.18,finishingRating:.10},OM:{techRating:.30,mentalRating:.24,finishingRating:.22,physicalRating:.14,defensiveRating:.10},LM:{techRating:.28,physicalRating:.22,mentalRating:.20,finishingRating:.20,defensiveRating:.10},RM:{techRating:.28,physicalRating:.22,mentalRating:.20,finishingRating:.20,defensiveRating:.10},LF:{finishingRating:.30,techRating:.24,physicalRating:.20,mentalRating:.16,defensiveRating:.10},RF:{finishingRating:.30,techRating:.24,physicalRating:.20,mentalRating:.16,defensiveRating:.10},HS:{finishingRating:.32,techRating:.24,mentalRating:.20,physicalRating:.14,defensiveRating:.10},ST:{finishingRating:.38,physicalRating:.22,techRating:.18,mentalRating:.14,defensiveRating:.08}};
function calcBaseOverall(player){ const ratings=calcRatings(player); const weights=OVERALL_WEIGHTS[player.mainPosition]||{techRating:.2,finishingRating:.2,mentalRating:.2,physicalRating:.2,defensiveRating:.2}; return Math.round(Object.entries(weights).reduce((s,[k,w])=>s + (ratings[k]||0)*w, 0)); }
function calcDevelopmentOverall(baseOverall,potentialOverall,potentialUsage){ return baseOverall + ((potentialOverall-baseOverall)*(potentialUsage/10)); }
function calcOverall(dev, form, fitness, morale){ const factor = 1 + ((fitness-80)/10)*0.005 + ((form-80)/10)*0.01 + ((morale-80)/10)*0.01; return Math.round(dev*factor); }
function applyDefinitionEffects(player, defs){ defs.filter(Boolean).forEach(def=>{ const scale=Number(def.ageEffectMultipliers?.[ageBucket(player.age)]||1); def.effects.forEach(effect=>{ if(effect.attribute && effect.attribute!=='-'){ player[effect.attribute]=clamp(Math.round((player[effect.attribute]||0)+(effect.delta*scale)),1,99); } }); }); }
function estimateClubStrengthTarget(club, league){ return Math.round((league?.standardPlayerOverall||60) + ((Number(club.prestige||5)-5)*0.8) + ((Number(club.financialPower||5)-5)*0.5) + ((Number(club.fanbase||5)-5)*0.25)); }
function qualityBandForIndex(index,r){ const role=index<11?'starters':index<18?'bench':'reserve'; const bands={starters:[{k:'low',w:4,a:-8,b:-5},{k:'below',w:18,a:-4,b:-2},{k:'average',w:36,a:-1,b:1},{k:'above',w:27,a:2,b:4},{k:'elite',w:15,a:5,b:8}],bench:[{k:'low',w:10,a:-8,b:-5},{k:'below',w:26,a:-4,b:-2},{k:'average',w:40,a:-1,b:1},{k:'above',w:18,a:2,b:4},{k:'elite',w:6,a:5,b:8}],reserve:[{k:'low',w:21,a:-8,b:-5},{k:'below',w:34,a:-4,b:-2},{k:'average',w:31,a:-1,b:1},{k:'above',w:11,a:2,b:4},{k:'elite',w:3,a:5,b:8}]}; return weightedPick(bands[role], x=>x.w, r); }
function targetOverallForPlayer(club, league, index, r){ const band=qualityBandForIndex(index,r); const role=index<11?'starters':index<18?'bench':'reserve'; const tierMod={starters:1.5,bench:0,reserve:-2.5}[role]; const clubDelta=(estimateClubStrengthTarget(club, league)-(league?.standardPlayerOverall||60))*({starters:.55,bench:.35,reserve:.2}[role]); return Math.round((league?.standardPlayerOverall||60) + randomInt(r,band.a,band.b) + tierMod + clubDelta); }
function talentFromPotential(overall,potentialOverall,reliability){ const target=Number(potentialOverall||overall||0); const rel=Number(reliability||5); const halfStars = clamp(Math.round((target - 61) / 6), 2, 10); const reliabilityAdj = rel>=8 ? 0.5 : rel<=3 ? -0.5 : 0; return clamp(Math.round(halfStars + reliabilityAdj), 1, 10); }
function makeStarHtml(fillPercent){ return '<span class="kf-star" style="position:relative;display:inline-block;width:0.95em;height:1em;line-height:1;vertical-align:middle;margin-right:0.06em"><span aria-hidden="true" style="position:absolute;inset:0;color:#5f6879">★</span><span aria-hidden="true" style="position:absolute;inset:0;width:'+fillPercent+'%;overflow:hidden;color:#f3cf62;white-space:nowrap">★</span></span>'; }
function starsLine(talent){ const halfSteps=clamp(Math.round(Number(talent||0)),0,10); let html=''; for(let i=0;i<5;i++){ const remaining=halfSteps-(i*2); const fill=remaining>=2?100:remaining===1?50:0; html+=makeStarHtml(fill); } return html; }
function randomReliabilityForKnownSquad(r){ return randomInt(r,7,10); }
function randomReliabilityForForeignSquad(r){ return randomInt(r,2,5); }

const SHIRT_NUMBER_RULES={
  GK:[1,12,21,23],
  CB:[4,5,13,15,24],
  FB:[2,3,14,16,17,18],
  CM:[6,8,19,20,22],
  AM:[10,17,20,24],
  WG:[7,11,17,18,21,22],
  ST:[9,19,20,24,25]
};
function shirtCategoryForPosition(pos){
  if(pos==='TW') return 'GK';
  if(pos==='IV') return 'CB';
  if(pos==='LV' || pos==='RV') return 'FB';
  if(pos==='DM' || pos==='ZM') return 'CM';
  if(pos==='OM' || pos==='HS') return 'AM';
  if(pos==='LM' || pos==='RM' || pos==='LF' || pos==='RF') return 'WG';
  return 'ST';
}
function displayShirtNumber(player){ return player && (player.shirtNumber ?? player.squadSlot ?? ''); }
function compareByShirtNumber(a,b){ return Number(displayShirtNumber(a)||99)-Number(displayShirtNumber(b)||99) || Number(a.squadSlot||99)-Number(b.squadSlot||99) || String(a.fullName||'').localeCompare(String(b.fullName||''),'de'); }
function assignShirtNumbersForClub(leagueState, clubId){
  if(!leagueState || !leagueState.playersById) return;
  const club = leagueState && leagueState.clubsById ? leagueState.clubsById[clubId] : null;
  const players = club
    ? (club.playerIds||[]).map(id=>leagueState.playersById[id]).filter(Boolean)
    : Object.values(leagueState.playersById).filter(player=>player && player.clubId===clubId);
  if(!players.length) return;
  const used = new Set();
  const byCat = { GK:[], CB:[], FB:[], CM:[], AM:[], WG:[], ST:[] };
  players.forEach(player=>{ byCat[shirtCategoryForPosition(player.mainPosition)].push(player); });
  Object.values(byCat).forEach(arr=>arr.sort((a,b)=> Number(b.overall||0)-Number(a.overall||0) || Number(a.age||99)-Number(b.age||99) || Number(a.squadSlot||99)-Number(b.squadSlot||99)));
  function firstFree(preferred, start){
    for(const nr of preferred){ if(!used.has(nr)){ used.add(nr); return nr; } }
    let nr = start;
    while(used.has(nr)) nr += 1;
    used.add(nr);
    return nr;
  }
  byCat.GK.forEach(player=>{ player.shirtNumber = firstFree(SHIRT_NUMBER_RULES.GK, 30); });
  [['CB',26],['FB',26],['CM',26],['AM',26],['WG',26],['ST',26]].forEach(([cat, start])=>{
    byCat[cat].forEach(player=>{ player.shirtNumber = firstFree(SHIRT_NUMBER_RULES[cat], start); });
  });
}
function ensureShirtNumbers(state){
  if(!state || !state.clubsById || !state.playersById) return state;
  Object.keys(state.clubsById).forEach(clubId=>{
    const players = Object.values(state.playersById).filter(player=>player && player.clubId===clubId);
    const hasExplicit = players.some(player=>player && Number.isFinite(Number(player.shirtNumber)));
    if(!hasExplicit) assignShirtNumbersForClub(state, clubId);
  });
  return state;
}
function applyUserKnowledgeReliability(state){ if(!state || !state.selectedClubId || !state.playersById) return state; const r=rnd(String(state.selectedClubId)+'|reliability'); const ownClubId=state.selectedClubId; Object.values(state.playersById).forEach(player=>{ if(!player) return; const nextRel = player.clubId===ownClubId ? randomReliabilityForKnownSquad(r) : randomReliabilityForForeignSquad(r); player.reliability = nextRel; player.talent = talentFromPotential(player.overall, player.potentialOverall, nextRel); player.displayedTalent = player.talent; }); return state; }
function estimateSalary(player, league, club){ const leagueSalary=budgetMillionsToSeasonCurrency(league?.standardSalarySeason||0.4); const qualityFactor=Math.max(.45, player.overall/Math.max(1, league?.standardPlayerOverall||60)); const prestigeFactor = 1 + ((Number(club.prestige||5)-5)*0.03); const ageFactor = player.age<=22 ? 0.93 : player.age>=31 ? 0.95 : 1; return Math.round(leagueSalary*0.04*qualityFactor*prestigeFactor*ageFactor); }
function estimateMarketValue(player, league){ const base = budgetMillionsToSeasonCurrency(league?.averagePlayerMarketValue||2); const overallFactor=Math.max(.25, (player.overall/Math.max(1, league?.standardPlayerOverall||60))**2); const potentialFactor=1 + Math.max(0, player.potentialOverall-player.overall)*0.025; const ageFactor=player.age<=21?1.2:player.age<=27?1:player.age<=31?.82:.6; return Math.round(base*overallFactor*potentialFactor*ageFactor*0.12); }
function resolveAssetPath(input){
  if(!input) return '';
  const raw = String(input);
  if(/^(data:|blob:|https?:|file:)/i.test(raw)) return raw;
  try{ return new URL(raw.replace(/^\.\//,''), projectRootHref()).href; }catch(_e){ return raw; }
}
function crestPath(club){ return resolveAssetPath(club && club.crestAsset); }
function homeKitPath(club){ return resolveAssetPath(club && club.homeKitAsset); }
function awayKitPath(club){ return resolveAssetPath(club && club.awayKitAsset); }
function clubInitials(club){ return club.clubName.split(/\s+/).filter(w=>!['FC','SC','SV','TSV','Union'].includes(w)).slice(0,2).map(w=>w[0]).join('').slice(0,2).toUpperCase() || club.clubName.slice(0,2).toUpperCase(); }
function resolveClubByIdInAnyState(clubId){ const career=getJSON(STORAGE_KEYS.career); if(career?.clubsById?.[clubId]) return career.clubsById[clubId]; const sel=getJSON(STORAGE_KEYS.selection); if(sel?.leagueState?.clubsById?.[clubId]) return sel.leagueState.clubsById[clubId]; return KFDB.clubs.find(c=>c.clubId===clubId)||null; }
function resolvePlayerById(playerId){ const career=getJSON(STORAGE_KEYS.career); return career?.playersById?.[playerId] || null; }
function getTeamTemplate(formation){ const counts={TW:2, IV:4, FB:4, CM:8, WM:4, ST:5}; const extras=[]; const posMap=formation.positionMap; Object.values(posMap).forEach(pos=>{ if(pos==='TW') return; if(['IV'].includes(pos)) extras.push('IV'); else if(['LV','RV'].includes(pos)) extras.push('FB'); else if(['DM','ZM','OM'].includes(pos)) extras.push('CM'); else if(['LM','RM'].includes(pos)) extras.push('WM'); else extras.push('ST'); }); const base=[]; for(let i=0;i<counts.TW;i++) base.push('TW'); for(let i=0;i<counts.IV;i++) base.push('IV'); for(let i=0;i<counts.FB;i++) base.push('FB'); for(let i=0;i<counts.CM;i++) base.push('CM'); for(let i=0;i<counts.WM;i++) base.push('WM'); for(let i=0;i<counts.ST;i++) base.push('ST'); while(base.length<25){ base.push(weightedPick(['CM','WM','ST','IV','FB'], x=>({CM:5,WM:4,ST:3,IV:3,FB:2}[x]), Math.random)); }
  return base.slice(0,25);
}
function generateLeagueState(countryName, leagueKey){ const seed = Date.now() + '_' + leagueKey; const r = rnd(seed); const clubs = clubsForLeague(leagueKey); const league = getLeagueRef(leagueKey);
  const leagueState = { seed, countryName, leagueKey, clubsById:{}, clubIds:[], playersById:{}, playerIds:[], tacticsByClubId:{}, generatedAt:new Date().toISOString() };
  let playerIndex=0;
  clubs.forEach(club=>{
    const formation = weightedPick(KFDB.formations, ()=>1, r);
    const template = getTeamTemplate(formation);
    const playerIds=[];
    template.forEach((groupKey, index)=>{
      playerIndex += 1;
      const age = chooseAge(r);
      const nationality = chooseNationality(leagueKey, r);
      const firstName = chooseFirstName(nationality, age, r);
      const lastName = chooseLastName(nationality, r);
      const mainPosition = chooseMainPositionForGroup(groupKey, r);
      const [secondaryPosition1, secondaryPosition2] = chooseSecondaryPositions(mainPosition, r);
      const targetOverall = targetOverallForPlayer(club, league, index, r);
      const skills = buildSkillProfile(mainPosition, targetOverall, r);
      const reliability = randomReliabilityForForeignSquad(r);
      const potentialOverall = clamp(targetOverall + (age<=19?randomInt(r,6,16):age<=23?randomInt(r,4,12):age<=27?randomInt(r,2,8):age<=31?randomInt(r,1,5):randomInt(r,0,3)), targetOverall, 99);
      const potentialUsage = Number((age<=19?randomInt(r,2,6):age<=23?randomInt(r,3,7):age<=27?randomInt(r,4,8):age<=31?randomInt(r,6,9):randomInt(r,7,10)).toFixed(1));
      const charDefs = chooseCharacterKeys(nationality, r);
      const typeDefs = chooseTypeKeys(mainPosition, r);
      const player = { playerId: (club.clubId + '_' + String(playerIndex).padStart(4,'0') + '_' + slugify(lastName)).slice(0,80), firstName, lastName, fullName: (firstName+' '+lastName).trim(), age, nationality, nationGroup: nationGroupMap[nationality]||'BAL', clubId: club.clubId, squadSlot:index+1, strongFoot: ['LV','LM','LF'].includes(mainPosition) ? weightedPick(['L','R'], x=>({L:75,R:25}[x]), r) : ['RV','RM','RF'].includes(mainPosition) ? weightedPick(['R','L'], x=>({R:75,L:25}[x]), r) : weightedPick(['R','L'], x=>({R:72,L:28}[x]), r), weakFoot: randomInt(r,1,5), mainPosition, secondaryPosition1, secondaryPosition2, reliability, character1: charDefs[0]?.key||null, character2: charDefs[1]?.key||null, playerType1: typeDefs[0]?.key||null, playerType2: typeDefs[1]?.key||null, form: randomInt(r,68,88), fitness: randomInt(r,78,95), morale: randomInt(r,72,90), heightCm: randomInt(r, mainPosition==='TW'?186:mainPosition==='IV'?182: mainPosition==='ST'?177:170, mainPosition==='TW'?199:mainPosition==='IV'?196: mainPosition==='ST'?194:188), weightKg: randomInt(r,68,94), potentialOverall, potentialUsage, ...skills };
      applyDefinitionEffects(player, charDefs);
      applyDefinitionEffects(player, typeDefs);
      const baseOverall = calcBaseOverall(player);
      const developmentOverall = Math.round(calcDevelopmentOverall(baseOverall, player.potentialOverall, player.potentialUsage));
      const overall = calcOverall(developmentOverall, player.form, player.fitness, player.morale);
      player.baseOverall = baseOverall;
      player.developmentOverall = developmentOverall;
      player.overall = overall;
      player.talent = talentFromPotential(overall, player.potentialOverall, reliability);
      player.displayedTalent = player.talent;
      player.salary = estimateSalary(player, league, club);
      player.salaryExpectation = player.salary;
      player.marketValue = estimateMarketValue(player, league);
      playerIds.push(player.playerId);
      leagueState.playersById[player.playerId] = player;
      leagueState.playerIds.push(player.playerId);
    });
    club.playerIds = playerIds;
    const salaryTargetFactor = (25 - randomInt(r,0,4)) / 25;
    const committedSalaryMio = sum(playerIds.map(id=>seasonCurrencyToMillions(leagueState.playersById[id].salary||0)));
    const targetSalaryMio = Number((Number(club.salaryBudget||0) * salaryTargetFactor).toFixed(2));
    if(committedSalaryMio > 0 && committedSalaryMio > targetSalaryMio){
      const scale = targetSalaryMio / committedSalaryMio;
      playerIds.forEach(id=>{
        const player = leagueState.playersById[id];
        player.salary = Math.max(10000, Math.round(Number(player.salary||0) * scale));
        player.salaryExpectation = player.salary;
      });
    }
    assignShirtNumbersForClub(leagueState, club.clubId);
    club.squadCount = playerIds.length;
    club.averageAge = Number(average(playerIds.map(id=>leagueState.playersById[id].age)).toFixed(1));
    club.squadStrength = Math.round(average(playerIds.map(id=>leagueState.playersById[id].overall)));
    club.squadMarketValue = seasonCurrencyToMillions(sum(playerIds.map(id=>leagueState.playersById[id].marketValue)));
    const lineup = buildLineupForClub({ club, leagueState, formationKey: formation.id });
    club.defaultFormationKey = formation.id;
    club.currentFormationKey = formation.id;
    club.startingElevenPlayerIds = Object.values(lineup.lineupPlayerIdsBySlotId);
    club.benchPlayerIds = lineup.benchPlayerIds;
    club.reservePlayerIds = lineup.reservePlayerIds;
    leagueState.tacticsByClubId[club.clubId] = lineup;
    leagueState.clubsById[club.clubId] = club;
    leagueState.clubIds.push(club.clubId);
  });
  // initial ranking by squad strength / prestige
  leagueState.clubIds.sort((a,b)=>{ const A=leagueState.clubsById[a], B=leagueState.clubsById[b]; return (B.squadStrength - A.squadStrength) || (B.prestige-A.prestige) || A.clubName.localeCompare(B.clubName,'de');});
  leagueState.clubIds.forEach((id,idx)=> leagueState.clubsById[id].leaguePosition = idx+1);
  return leagueState;
}
function slotFit(player, positionCode){ if(player.mainPosition===positionCode) return player.overall+6; if([player.secondaryPosition1, player.secondaryPosition2].includes(positionCode)) return player.overall+2; if((NEARBY_MAP[positionCode]||[]).includes(player.mainPosition)) return player.overall-1; return -999; }
function buildLineupForClub({ club, leagueState, formationKey }){ const formation = KFDB.formations.find(f=>f.id===formationKey) || KFDB.formations[0]; const players = (club.playerIds||[]).map(id=>leagueState.playersById[id]).filter(Boolean); const assigned = new Set(); const lineupPlayerIdsBySlotId={}; formation.occupiedSlots.forEach(slotId=>{ const pos=formation.positionMap[slotId]; const candidates=players.filter(p=>!assigned.has(p.playerId)).map(p=>({p,score:slotFit(p,pos)})).filter(x=>x.score>-900).sort((a,b)=>b.score-a.score); const winner=candidates[0]?.p; if(winner){ assigned.add(winner.playerId); lineupPlayerIdsBySlotId[slotId]=winner.playerId; } }); const rest=players.filter(p=>!assigned.has(p.playerId)).sort((a,b)=>b.overall-a.overall); return { formationKey:formation.id, formationLabel:formation.label, lineupPlayerIdsBySlotId, benchPlayerIds:rest.slice(0,7).map(p=>p.playerId), reservePlayerIds:rest.slice(7).map(p=>p.playerId) }; }
