function estimateSalary(player, league, club){
  const squadSizeTarget = 25;
  const perPlayerBase = budgetMillionsToSeasonCurrency(Number(club.salaryBudget||4) / squadSizeTarget);
  const overallFactor = clamp((player.overall / Math.max(1, Number(league?.standardPlayerOverall||60))), 0.72, 1.35);
  const potentialFactor = 1 + Math.max(0, Number(player.potentialOverall||player.overall) - Number(player.overall||0)) * 0.012;
  const ageFactor = player.age <= 21 ? 0.82 : player.age >= 32 ? 0.9 : 1;
  const prestigeFactor = 1 + ((Number(club.prestige||5) - 5) * 0.02);
  return Math.round(perPlayerBase * overallFactor * potentialFactor * ageFactor * prestigeFactor);
}
function computeClubSalaryRemaining(state, clubId){
  const club = state.clubsById[clubId];
  const committed = sum((club.playerIds||[]).map(id => Number(state.playersById[id]?.salary||0)));
  return Math.max(0, Number((Number(club.salaryBudget||0) - seasonCurrencyToMillions(committed)).toFixed(2)));
}
